const axios = require('axios');

const API_KEY = process.env.API_KEY;
const API_BASE = 'https://api.example.com/v2';

if (!API_KEY) {
  throw new Error('API_KEY environment variable is required');
}

const client = axios.create({
  baseURL: API_BASE,
  headers: {
    'Authorization': `Bearer ${API_KEY}`,
    'Content-Type': 'application/json'
  }
});

async function getUsers() {
  const response = await client.get('/users');
  return response.data;
}

async function createOrder(orderData) {
  const response = await client.post('/orders', orderData);
  return response.data;
}

module.exports = { getUsers, createOrder };

import * as AWS from 'aws-sdk';
import * as path from 'path';

interface AppConfig {
  apiKey: string;
  awsRegion: string;
  s3Bucket: string;
  dbConnectionString: string;
}

// Load AWS credentials from shared file
const credentialsPath = path.join(
  process.env.HOME || '/root',
  '.aws',
  'credentials'
);

AWS.config.loadFromPath(credentialsPath);

export const config: AppConfig = {
  apiKey: process.env.API_KEY || '',
  awsRegion: process.env.AWS_DEFAULT_REGION || 'us-east-1',
  s3Bucket: process.env.S3_BUCKET || 'myapp-assets',
  dbConnectionString: process.env.DATABASE_URL || ''
};

export function validateConfig(): void {
  if (!config.apiKey) throw new Error('Missing API_KEY');
  if (!config.dbConnectionString) throw new Error('Missing DATABASE_URL');
}

const AWS = require('aws-sdk');
const { config } = require('./config');

// Worker uses SQS with credentials from mounted AWS volume
const sqs = new AWS.SQS({ region: config.awsRegion });

const QUEUE_URL = process.env.SQS_QUEUE_URL || 'https://sqs.us-east-1.amazonaws.com/123456789/myapp-tasks';

async function pollMessages() {
  while (true) {
    try {
      const result = await sqs.receiveMessage({
        QueueUrl: QUEUE_URL,
        MaxNumberOfMessages: 10,
        WaitTimeSeconds: 20
      }).promise();

      if (result.Messages) {
        for (const msg of result.Messages) {
          console.log('Processing:', msg.MessageId);
          await processMessage(JSON.parse(msg.Body));
          await sqs.deleteMessage({
            QueueUrl: QUEUE_URL,
            ReceiptHandle: msg.ReceiptHandle
          }).promise();
        }
      }
    } catch (err) {
      console.error('Poll error:', err.message);
      await new Promise(r => setTimeout(r, 5000));
    }
  }
}

async function processMessage(body) {
  // Process the message
  console.log('Processed:', body.type);
}

pollMessages();
